    function createLabelIcon(labelText: string): google.maps.Icon {
        const fontSize = 18;
        const padding = 8;
        const font = `${fontSize}px sans-serif`;

        const tempCanvas = document.createElement("canvas");
        const ctx = tempCanvas.getContext("2d")!;
        ctx.font = font;
        const textWidth = ctx.measureText(labelText).width;

        const width = Math.ceil(textWidth + padding * 2);
        const height = fontSize + padding;

        const canvas = document.createElement("canvas");
        canvas.width = width;
        canvas.height = height;

        const ctx2 = canvas.getContext("2d")!;
        ctx2.font = font;;
        ctx2.fillStyle = "#FFFFFF"; // ⭐ 明亮底色（淡黃）
        ctx2.fillRect(0, 0, width, height); // ⭐ 加上底色背景

        ctx2.fillStyle = "orange"
        ctx2.textAlign = "center";
        ctx2.textBaseline = "middle";
        ctx2.fillText(labelText, width / 2, height / 2);

        return {
            url: canvas.toDataURL(),
            scaledSize: new google.maps.Size(width, height),
            anchor: new google.maps.Point(width / 2, height)  // 下方對齊
        };
    }

