    //togoogle
    //const userId = 'testuser'; // ✅

    function saveCurrentDrawings() {
        const geoJson: any = {
            type: 'FeatureCollection',
            features: []
        };

        overlays.forEach((overlay) => {
            const color= getColorForOverlay(overlay);
            if (
                overlay instanceof google.maps.Marker &&
                overlay.getIcon()?.url?.startsWith("data:image/png;base64") // ✅ 用 data URL 判斷是 label
            ) {
                const pos = overlay.getPosition();
                if (pos) {
                    // 從 icon 中還原文字（假設你有儲存在 overlayMetadata）
                    const meta = overlayMetadata.get(overlay);
                    const labelText = meta?.text || "";

                    geoJson.features.push({
                        type: 'Feature',
                        geometry: {
                            type: 'Point',
                            coordinates: [pos.lng(), pos.lat()]
                        },
                        properties: {
                            shape: 'label',
                            label: labelText
                        }
                    });
                }
            }
            else if (overlay instanceof google.maps.InfoWindow && overlay.getPosition) {
                const pos = overlay.getPosition();
                const label = overlay.getContent()?.replace(/<[^>]*>?/gm, ''); // 去除 HTML
                if (pos && label) {
                    geoJson.features.push({
                        type: 'Feature',
                        geometry: {
                            type: 'Point',
                            coordinates: [pos.lng(), pos.lat()]
                        },
                        properties: { shape: 'label', label }
                    });
                }
            }
            else if (overlay instanceof google.maps.Marker && overlay.getIcon()?.url?.includes('chart.apis.google.com')) {
                const pos = overlay.getPosition();
                if (pos) {
                    const labelText = decodeURIComponent(overlay.getIcon().url.split('|').pop() || '');
                    geoJson.features.push({
                        type: 'Feature',
                        geometry: {
                            type: 'Point',
                            coordinates: [pos.lng(), pos.lat()]
                        },
                        properties: {
                            shape: 'label',
                            label: labelText
                        }
                    });
                }
            }
            else if (overlay instanceof google.maps.Marker) {
                const pos = overlay.getPosition();
                if (pos) {
                    geoJson.features.push({
                        type: 'Feature',
                        geometry: {
                            type: 'Point',
                            coordinates: [pos.lng(), pos.lat()]
                        },
                        properties: { shape: 'marker', color }
                    });
                }
            }
            else if (overlay instanceof google.maps.Polyline) {
                const path = overlay.getPath().getArray();
                const coordinates = path.map((latlng) => [latlng.lng(), latlng.lat()]);
                geoJson.features.push({
                    type: 'Feature',
                    geometry: {
                        type: 'LineString',
                        coordinates
                    },
                    properties: { shape: 'polyline', color }
                });
            }
            else if (overlay instanceof google.maps.Polygon) {
                const paths = overlay.getPaths().getArray().map(path =>
                    path.getArray().map(latlng => [latlng.lng(), latlng.lat()])
                );
                geoJson.features.push({
                    type: 'Feature',
                    geometry: {
                        type: 'Polygon',
                        coordinates: paths
                    },
                    properties: { shape: 'polygon', color }
                });
            }
            else if (overlay instanceof google.maps.Rectangle) {
                const bounds = overlay.getBounds();
                if (bounds) {
                    geoJson.features.push({
                        type: 'Feature',
                        geometry: {
                            type: 'Rectangle',
                            coordinates: [
                                [bounds.getSouthWest().lng(), bounds.getSouthWest().lat()],
                                [bounds.getNorthEast().lng(), bounds.getNorthEast().lat()]
                            ]
                        },
                        properties: { shape: 'rectangle', color }
                    });
                }
            }
            else if (overlay instanceof google.maps.Circle) {
                const center = overlay.getCenter();
                const radius = overlay.getRadius();
                if (center && radius) {
                    geoJson.features.push({
                        type: 'Feature',
                        geometry: {
                            type: 'Circle',
                            coordinates: [center.lng(), center.lat()],
                            radius: radius
                        },
                        properties: { shape: 'circle', color }
                    });
                }
            }
        });

        fetch('http://211.23.16.134:8088/apitest/drawings', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                userId: typeof userId === 'string' ? userId : userId.value,
                geoJson,
                name: '自訂圖層',
                timestamp: new Date().toISOString()
            })
        });
    }

