        };

        const position = { lat: y, lng: x };
        const marker = new google.maps.Marker({
            position,
            map: pMap.value,
            title,
            icon: markerIcon,
            zIndex: 3000
        });

        if (!sharedInfoWindow) {
            sharedInfoWindow = new google.maps.InfoWindow();
