    //togoogle
    function getColorByIntensity(level) {
        switch (level) {
            case '1': return '#00FF00';
            case '2': return '#FFFF00';
            case '3': return '#FFA500';
            case '4': return '#FF0000';
            default: return '#888888';
        }
    }

    //togoogle
    function lightenColor(color: string, percent: number) {
        const num = parseInt(color.replace("#", ""), 16);
        const amt = Math.round(2.55 * percent);
        const R = (num >> 16) + amt;
        const G = (num >> 8 & 0x00FF) + amt;
        const B = (num & 0x0000FF) + amt;
        return "#" + (
            0x1000000 +
            (R < 255 ? (R < 1 ? 0 : R) : 255) * 0x10000 +
            (G < 255 ? (G < 1 ? 0 : G) : 255) * 0x100 +
            (B < 255 ? (B < 1 ? 0 : B) : 255)
        ).toString(16).slice(1);
    }
    function getDefaultStrokeWeightByLayerId(layerId: string): number {
        switch (layerId) {
            case 'layer24': return 3; // 治理計畫線
            case 'layer25': return 6; // 用地範圍線
            case 'layer26': return 9; // 河川區域線
            default: return 2;
        }
    }

    function getDefaultZIndexByLayerId(layerId: string): number {
        switch (layerId) {
            case 'layer24': return 3;
            case 'layer25': return 2;
            case 'layer26': return 1;
            default: return 1;
        }
    }
    //togoogle 線段中點
    function getFeaturePosition(f: google.maps.Data.Feature): google.maps.LatLng | null {
        const geom = f.getGeometry();
        if (!geom) return null;

        switch (geom.getType()) {
            case 'Point':
                return (geom as google.maps.Data.Point).get();
            case 'LineString':
                const path = (geom as google.maps.Data.LineString).getArray();
                return path[Math.floor(path.length / 2)] || null;
            case 'Polygon':
                const rings = (geom as google.maps.Data.Polygon).getArray();
                const firstRing = rings[0];
                return firstRing[Math.floor(firstRing.length / 2)] || null;
            default:
                return null;
        }
    }

